    sin(t*0.5*frq1+3.5)*amp1 + cos(t*1.1*frq1+0.5)*amp1*0.35,
    cos(t*0.8*frq1+2.4)*amp1*0.85 + sin(t*1.4*frq1+2.0)*amp1*0.3
